Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id validationErrors { errorCode errorMessage objectType } } }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.id → CART_ID]
[GQL-OP probe_all_locations]
  query {
    cartPickupLocations(cartId: "{{CART_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 200 sort: "name:desc") {
      totalCount
      items { id name }
    }
  }
[GQL-EXEC probe_all_locations]
[GQL-CAPTURE probe_all_locations.data.cartPickupLocations.items.0.id → LAST_LOCATION_ID]
[GQL-OP set_shipment_pickup]
  mutation {
    addOrUpdateCartShipment(command: {
      storeId: "{{STORE_ID}}" userId: "{{USER_ID}}"
      shipment: {
        shipmentMethodCode: "BuyOnlinePickupInStore"
        shipmentMethodOption: "Pickup"
        pickupLocationId: "{{LAST_LOCATION_ID}}"
        price: 0
      }
    }) {
      id
      shipments { shipmentMethodCode shipmentMethodOption pickupLocation { id } fulfillmentCenterId }
    }
  }
[GQL-EXEC set_shipment_pickup]
[GQL-OP query_keyword_exclude]
  query {
    cartPickupLocations(cartId: "{{CART_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 5 keyword: "xyzabc_no_such_location_999") {
      totalCount
      items { id name }
    }
  }
[GQL-EXEC query_keyword_exclude]
[GQL-OP query_paged_small]
  query {
    cartPickupLocations(cartId: "{{CART_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 1 sort: "name:asc") {
      totalCount
      items { id name }
    }
  }
[GQL-EXEC query_paged_small]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_clear]

[AUTH role=ORG_USER]
[GQL-OP list_locations]
  query {
    pickupLocations(storeId: "{{STORE_ID}}" first: 20 sort: "name:asc") {
      totalCount
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
      items {
        id isActive name description contactEmail contactPhone
        workingHours deliveryDays storageDays geoLocation
        address {
          id key name organization countryCode countryName
          regionId regionName city postalCode line1 line2
          phone email outerId description addressType
        }
      }
    }
  }
[GQL-EXEC list_locations]
[GQL-OP list_locations_keyword]
  query {
    pickupLocations(storeId: "{{STORE_ID}}" first: 5 keyword: "Main") {
      totalCount
      items { id name address { city countryCode } }
    }
  }
[GQL-EXEC list_locations_keyword]

[AUTH role=ORG_USER]
[GQL-OP setup_prod]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prod]
[GQL-CAPTURE setup_prod.data.products.items.0.id → PRODUCT_ID]
[GQL-OP product_locations]
  query {
    productPickupLocations(productId: "{{PRODUCT_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 20 sort: "name:asc") {
      totalCount
      pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
      items {
        id isActive name description contactEmail contactPhone
        workingHours deliveryDays storageDays geoLocation
        availabilityType availabilityNote availableQuantity
        address {
          id key name organization countryCode countryName
          regionId regionName city postalCode line1 line2
          phone email outerId description addressType
        }
      }
    }
  }
[GQL-EXEC product_locations]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id validationErrors { errorCode errorMessage objectType } } }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.id → CART_ID]
[GQL-OP probe_baseline]
  query {
    cartPickupLocations(cartId: "{{CART_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 5) {
      totalCount items { id name address { city } }
    }
  }
[GQL-EXEC probe_baseline]
[GQL-CAPTURE probe_baseline.data.cartPickupLocations.items.0.address.city → SEED_CITY]
[GQL-OP probe_keyword_match]
  query {
    cartPickupLocations(cartId: "{{CART_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 200 keyword: "{{SEED_CITY}}") {
      totalCount items { id name address { city } }
    }
  }
[GQL-EXEC probe_keyword_match]
[GQL-OP probe_keyword_nomatch]
  query {
    cartPickupLocations(cartId: "{{CART_ID}}" storeId: "{{STORE_ID}}" cultureName: "en-US" first: 5 keyword: "xyzabc_no_such_location_999") {
      totalCount items { id }
    }
  }
[GQL-EXEC probe_keyword_nomatch]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_clear]

